// client/src/pages/customer/CustomerDashboard.js
import React, { useState, useEffect } from "react";
import api from "../../services/api";
import useAuth from "../../hooks/useAuth";
import io from "socket.io-client";

const CustomerDashboard = () => {
  const [parcels, setParcels] = useState([]);
  const [form, setForm] = useState({
    pickupAddress: "",
    deliveryAddress: "",
    parcelDetails: { type: "Document", size: "Small" },
    paymentType: "Prepaid",
  });
  const { logout } = useAuth();

  useEffect(() => {
    fetchHistory();

    const socket = io("http://localhost:5001");
    socket.on("status_update", (data) => {
      setParcels((prev) =>
        prev.map((p) =>
          p._id === data.parcelId
            ? {
                ...p,
                status: data.status,
                trackingHistory: [
                  ...p.trackingHistory,
                  {
                    status: data.status,
                    location: data.location,
                    timestamp: new Date(),
                  },
                ],
              }
            : p
        )
      );
    });

    return () => socket.disconnect();
  }, []);

  const fetchHistory = async () => {
    try {
      const { data } = await api.get("/parcels/history");
      setParcels(data);
    } catch (error) {
      console.error("Failed to fetch history", error);
    }
  };

  const handleBooking = async (e) => {
    e.preventDefault();
    try {
      await api.post("/parcels", form);
      setForm({
        pickupAddress: "",
        deliveryAddress: "",
        parcelDetails: { type: "Document", size: "Small" },
        paymentType: "Prepaid",
      });
      fetchHistory(); // Refresh list after booking
    } catch (error) {
      console.error("Booking failed", error);
    }
  };

  // Simplified form change handler
  const handleChange = (e) => {
    const { name, value } = e.target;
    if (name === "type" || name === "size") {
      setForm((prev) => ({
        ...prev,
        parcelDetails: { ...prev.parcelDetails, [name]: value },
      }));
    } else {
      setForm((prev) => ({ ...prev, [name]: value }));
    }
  };

  return (
    <div>
      <h1>Customer Dashboard</h1>
      <button onClick={logout}>Logout</button>
      <hr />
      <h2>Book a Parcel</h2>
      <form onSubmit={handleBooking}>
        <input
          name="pickupAddress"
          value={form.pickupAddress}
          onChange={handleChange}
          placeholder="Pickup Address"
          required
        />
        <input
          name="deliveryAddress"
          value={form.deliveryAddress}
          onChange={handleChange}
          placeholder="Delivery Address"
          required
        />
        <input
          name="type"
          value={form.parcelDetails.type}
          onChange={handleChange}
          placeholder="Parcel Type (e.g., Electronics)"
          required
        />
        <select
          name="size"
          value={form.parcelDetails.size}
          onChange={handleChange}
        >
          <option value="Small">Small</option>
          <option value="Medium">Medium</option>
          <option value="Large">Large</option>
        </select>
        <select
          name="paymentType"
          value={form.paymentType}
          onChange={handleChange}
        >
          <option value="Prepaid">Prepaid</option>
          <option value="COD">COD</option>
        </select>
        <button type="submit">Book Now</button>
      </form>
      <hr />
      <h2>My Bookings</h2>
      {parcels.length > 0 ? (
        <ul>
          {parcels.map((p) => (
            <li key={p._id}>
              ID: {p._id} | Status: <strong>{p.status}</strong> | Agent:{" "}
              {p.deliveryAgent?.name || "Unassigned"}
              <p>Tracking:</p>
              <ul>
                {p.trackingHistory.map((t, i) => (
                  <li key={i}>
                    {t.status} at {t.location || "N/A"} on{" "}
                    {new Date(t.timestamp).toLocaleString()}
                  </li>
                ))}
              </ul>
            </li>
          ))}
        </ul>
      ) : (
        <p>No bookings yet.</p>
      )}
      {/* Note: Real-time map tracking would be a separate, more complex component */}
    </div>
  );
};

export default CustomerDashboard;
